const item = $input.first().json;
const body = item.body || {};
const required = ['idea', 'target_audience', 'monetization_guess'];
const sanitize = (value) =>
  String(value)
    .replace(/<[^>]*>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

const cleaned = {};
const missing = [];

for (const field of required) {
  const value = body[field];
  if (typeof value !== 'string' || !value.trim()) {
    missing.push(field);
  } else {
    cleaned[field] = sanitize(value);
  }
}

if (missing.length) {
  return [
    {
      json: {
        is_valid: false,
        http_status: 400,
        initial_response: {
          error: 'missing or invalid fields',
          required,
          missing,
        },
      },
    },
  ];
}

const runId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (char) => {
  const random = Math.floor(Math.random() * 16);
  const value = char === 'x' ? random : ((random & 0x3) | 0x8);
  return value.toString(16);
});

return [
  {
    json: {
      ...cleaned,
      input_payload: cleaned,
      research_context: null,
      analysis_outputs: {},
      warnings: [],
      run_id: runId,
      n8n_execution_id: $execution.id,
      is_valid: true,
      http_status: 202,
      initial_response: {
        run_id: runId,
        status: 'accepted',
        status_url: '/webhook/pmf-brainstorm-status?run_id=' + runId,
      },
    },
  },
];

return [
  {
    json: {
      ...$('Validate Intake').first().json,
    },
  },
];

